remediation.fix:
Sanitize the local-import-file parameter to prevent directory traversal:
$_file = basename($data->get('local-import-file'));
$file = Platform::getPublicDirectory() . '/' . $_file;
$realFile = realpath($file);
$realBase = realpath(Platform::getPublicDirectory());
if (!$realFile || strpos($realFile, $realBase) !== 0) {
    Notification::error('Invalid file path.');
    $this->response->error();
}
